// src/pages/Leave/LeavePage.js

import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle, Send,
  BarChart2, Calendar, Edit3, Bell, RefreshCw, Users,
  TrendingUp, AlertTriangle, Settings, FileText, Upload,
  ChevronDown, ChevronUp, Filter, Download, Search,
  ArrowRightLeft, Layers, Shield, RotateCcw, Trash2
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import {
  Modal, Badge, SkeletonCard, EmptyState, InlineSpinner, StatCard,
} from '../../components/common';
import { useAuth } from '../../context/AuthContext';

// ─── Status normalisation ────────────────────────────────────────────────────
const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PendingHR: 'Pending HR',
  PENDING_HR: 'Pending HR', APPROVED: 'Approved', REJECTED: 'Rejected',
  CANCELLED: 'Cancelled', CANCELED: 'Cancelled', DRAFT: 'Draft',
  Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
  submitted: 'Submitted', pending: 'Pending Approval',
  approved: 'Approved', rejected: 'Rejected', cancelled: 'Cancelled',
};

const STATUS_OPTIONS = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER', 'PENDINGHR', 'SUBMITTED', 'PENDING', 'DRAFT', 'PENDINGDOCTOR']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s =>
  ['APPROVED', 'REJECTED', 'CANCELLED', 'CANCELED', 'Approved', 'Rejected', 'Cancelled', 'approved', 'rejected', 'cancelled'].includes(normStatus(s));

// ─── Leave Balance Card ──────────────────────────────────────────────────────
function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name      = balance.leaveTypeName  || balance.LeaveTypeName  || balance.name || 'Leave';
  const used      = Number(balance.usedDays      ?? balance.UsedDays      ?? 0);
  const pending   = Number(balance.pendingDays   ?? balance.PendingDays   ?? 0);
  const entitled  = Number(balance.entitledDays  ?? balance.EntitledDays  ?? 0);
  const carryOver = Number(balance.carryOverDays ?? balance.CarryOverDays ?? 0);
  const adjusted  = Number(balance.adjustedDays  ?? balance.AdjustedDays  ?? 0);
  const remaining = Number(
    balance.remainingDays ?? balance.RemainingDays ??
    Math.max(0, entitled + carryOver + adjusted - used - pending)
  );
  const maxDays = Number(balance.maxDaysPerYear ?? (entitled + carryOver + adjusted));
  const total   = maxDays || (used + remaining) || 1;
  const pct     = total > 0 ? Math.round((remaining / total) * 100) : 0;

  const COLOR_MAP = {
    Annual: 'var(--blue)', Sick: 'var(--green)', Medical: 'var(--green)',
    Emergency: 'var(--red)', Accidental: 'var(--red)', Sabbatical: 'var(--purple)',
    Maternity: 'var(--purple)', Paternity: 'var(--purple)',
  };
  const color = Object.entries(COLOR_MAP).find(([k]) => name.includes(k))?.[1] || 'var(--gold)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
          {name}
        </div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}>
        <div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} />
      </div>
      <div className="stat-card-meta">
        <span>{used} used{pending > 0 ? ` · ${pending} pending` : ''}{carryOver > 0 ? ` · ${carryOver} carried` : ''}</span>
        <span>{pct}%</span>
      </div>
    </div>
  );
}

// ─── Request Row ─────────────────────────────────────────────────────────────
function RequestRow({ req, onAction, onEdit, isManager, userRole }) {
  const [acting, setActing] = useState('');
  const name    = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.leaveTypeName || req.LeaveTypeName || req.type || '—';
  const from    = (req.StartDate || req.startDate) ? new Date(req.StartDate || req.startDate).toLocaleDateString() : '—';
  const to      = (req.EndDate   || req.endDate)   ? new Date(req.EndDate   || req.endDate).toLocaleDateString()   : '—';
  const days    = req.TotalDays ?? req.totalDays ?? req.numberOfDays ?? req.days ?? '—';
  const status  = req.Status || req.status || 'SUBMITTED';
  const id      = req.LeaveRequestID || req.leaveRequestId || req.id;
  const empName = req.Employee?.FullName || req.employee?.FullName || req.employeeName
                || [req.employee?.firstName, req.employee?.lastName].filter(Boolean).join(' ') || '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal      = isFinalStatus(status);
  const isCancellable = !isFinal;
  const displayLabel = STATUS_LABEL[status] || status;

  const statusStyle = {
    display: 'inline-block', padding: '3px 10px', borderRadius: 20,
    fontSize: '0.75rem', fontWeight: 600,
    background: normStatus(status) === 'APPROVED' ? 'rgba(34,197,94,0.15)'
              : normStatus(status) === 'REJECTED'  ? 'rgba(239,68,68,0.15)'
              : normStatus(status) === 'CANCELLED' ? 'rgba(156,163,175,0.15)'
              : 'rgba(251,191,36,0.15)',
    color:      normStatus(status) === 'APPROVED' ? '#16a34a'
              : normStatus(status) === 'REJECTED'  ? '#dc2626'
              : normStatus(status) === 'CANCELLED' ? '#6b7280'
              : '#b45309',
  };

  return (
    <tr style={{ borderBottom: '1px solid var(--border-light)' }}>
      <td style={{ padding: '12px 8px' }}>
        <div style={{ fontWeight: 500 }}>{name}</div>
        {(req.Reason || req.reason) && (
          <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: 2 }}>
            {(req.Reason || req.reason).slice(0, 50)}…
          </div>
        )}
      </td>
      {isManager && <td style={{ padding: '12px 8px' }}><div style={{ fontWeight: 500 }}>{empName}</div></td>}
      <td style={{ padding: '12px 8px', fontSize: '0.82rem' }}>{from} → {to}</td>
      <td style={{ padding: '12px 8px' }}>{days !== '—' ? `${days} day${days !== 1 ? 's' : ''}` : '—'}</td>
      <td style={{ padding: '12px 8px' }}><span style={statusStyle}>{displayLabel}</span></td>
      <td style={{ padding: '12px 8px' }}>
        <div style={{ display: 'flex', gap: 6 }}>
          {isManager && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>
                {acting === 'approve' ? <InlineSpinner /> : <><Check size={13} /> Approve</>}
              </button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>
                {acting === 'reject' ? <InlineSpinner /> : <><X size={13} /> Reject</>}
              </button>
            </>
          )}
          {!isManager && isCancellable && (
            <>
              <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)}>
                <Edit3 size={14} /> Edit
              </button>
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>
                {acting === 'cancel' ? <InlineSpinner /> : 'Cancel'}
              </button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── Submit Leave Form ───────────────────────────────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '' });
  const [errors, setErrors] = useState({});
  const set = (k, v) => { setForm(f => ({ ...f, [k]: v })); setErrors(e => ({ ...e, [k]: '' })); };

  const handle = () => {
    if (!form.LeaveTypeID || !form.startDate || !form.endDate) return;
    onSubmit({
      LeaveTypeID: parseInt(form.LeaveTypeID, 10),
      StartDate: form.startDate,
      EndDate: form.endDate,
      Reason: form.reason || null,
    });
  };

  return (
    <>
      <div className="form-group">
        <label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => set('LeaveTypeID', e.target.value)}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => (
            <option key={t.LeaveTypeID || t.id} value={t.LeaveTypeID || t.id}>{t.LeaveTypeName || t.name}</option>
          ))}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label required">Start Date</label>
          <input className="form-input" type="date" value={form.startDate} onChange={e => set('startDate', e.target.value)} />
        </div>
        <div className="form-group">
          <label className="form-label required">End Date</label>
          <input className="form-input" type="date" value={form.endDate} min={form.startDate || undefined} onChange={e => set('endDate', e.target.value)} />
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Reason</label>
        <textarea className="form-textarea" rows={2} value={form.reason} onChange={e => set('reason', e.target.value)} placeholder="Briefly describe the reason…" />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 16 }}>
        <button className="btn btn-primary" onClick={handle} disabled={loading || !form.LeaveTypeID || !form.startDate || !form.endDate}>
          {loading ? <InlineSpinner /> : 'Submit Request'}
        </button>
      </div>
    </>
  );
}

// ─── MAIN LEAVE PAGE COMPONENT ───────────────────────────────────────────────

export default function LeavePage() {
  const { user } = useAuth();

  // ROBUST ROLE CHECKING (Case insensitive, handles nulls safely)
  const roleStr = (user?.role || '').toLowerCase();
  const isManager = roleStr.includes('manager') || roleStr.includes('admin');
  const isHR = roleStr.includes('hr') || roleStr.includes('admin');

  const [tab, setTab] = useState('history');

  // Data State
  const [myRequests, setMyRequests] = useState([]);
  const [teamRequests, setTeamRequests] = useState([]); 
  const [allRequests, setAllRequests] = useState([]);   
  const [balances, setBalances] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [leaveTypes, setLeaveTypes] = useState([]);

  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');

  // Modals state
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);

  // ─── FAULT-TOLERANT DATA LOADING ───────────────────────────────────────────
  // Instead of Promise.all (which crashes entirely if 1 API fails), we handle them individually.
  const loadDashboardData = useCallback(async () => {
    setLoading(true);

    // Helper to safely fetch data without crashing
    const fetchSafe = async (apiCall, fallback = []) => {
      try { const res = await apiCall(); return res.data || fallback; } 
      catch (e) { return fallback; }
    };

    // 1. Core Data
    const reqData = await fetchSafe(() => leaveAPI.getMyRequests({ status: filterStatus }));
    const balData = await fetchSafe(() => leaveAPI.getMyBalances());
    const notifData = await fetchSafe(() => notificationAPI.getNotifications());
    const typeData = await fetchSafe(() => (leaveAPI.getTypes ? leaveAPI.getTypes() : Promise.reject()));

    setMyRequests(reqData);
    setBalances(balData);
    setNotifications(notifData);
    setLeaveTypes(typeData.length ? typeData : balData.map(b => b.LeaveType || b.leaveType).filter(Boolean));

    // 2. Manager Sync
    if (isManager) {
      const inboxData = await fetchSafe(() => leaveAPI.getManagerInbox());
      setTeamRequests(inboxData);
    }

    // 3. HR Sync
    if (isHR) {
      const allData = await fetchSafe(() => leaveAPI.listAll({ status: filterStatus }));
      setAllRequests(allData.requests || allData || []);
    }

    setLoading(false);
  }, [filterStatus, isManager, isHR]);

  useEffect(() => {
    loadDashboardData();
  }, [loadDashboardData]);

  // ─── HANDLERS ─────────────────────────────────────────────────────────────

  const handleSubmitLeave = async (formData) => {
    setActionLoading(true);
    try {
      await leaveAPI.submit(formData);
      toast.success("Leave request submitted successfully");
      setIsSubmitModalOpen(false);
      await loadDashboardData();
    } catch (err) { 
      toast.error(err.response?.data?.message || "Failed to submit request. Check API connection."); 
    } finally { setActionLoading(false); }
  };

  const handleManagerAction = async (id, action) => {
    setActionLoading(true);
    try {
      await leaveAPI.approveReject(id, { decision: action.toUpperCase(), comments: 'Processed via Dashboard' });
      toast.success(`Request ${action}d successfully`);
      await loadDashboardData();
    } catch (err) { 
      toast.error(err.response?.data?.message || `Failed to ${action} request`); 
    } finally { setActionLoading(false); }
  };

  // ─── UI Rendering ──────────────────────────────────────────────────────────

  if (loading && myRequests.length === 0 && balances.length === 0) return <SkeletonCard count={4} />;

  // Define allowed tabs based on safe role checks
  const availableTabs = [
    { id: 'history', label: 'My Leave History' },
    ...(isManager ? [
      { id: 'team', label: 'Team Approval Inbox' },
      { id: 'delegation', label: 'Delegation' }
    ] : []),
    ...(isHR ? [
      { id: 'hr-dashboard', label: 'Company Overview' },
      { id: 'settings', label: 'HR Admin Settings' }
    ] : [])
  ];

  return (
    <div className="leave-module" style={{ padding: '2rem' }}>

      {/* Module Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h1 style={{ fontSize: '1.875rem', fontWeight: 700, color: 'var(--text-primary)' }}>Leave Management</h1>
          <p style={{ color: 'var(--text-secondary)' }}>Track balances, submit requests, and manage approvals.</p>
        </div>
        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <button className="btn btn-ghost" style={{ position: 'relative' }}>
            <Bell size={20} />
            {notifications.length > 0 && <span style={{ position: 'absolute', top: 0, right: 0, background: 'red', color: 'white', borderRadius: '50%', width: 14, height: 14, fontSize: '10px' }}>{notifications.length}</span>}
          </button>

          {/* THE NEW REQUEST BUTTON - Fixed onClick Handler */}
          <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}>
            <Plus size={18} style={{ marginRight: 8 }} /> New Request
          </button>
        </div>
      </div>

      {/* Balances */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem', marginBottom: '2.5rem' }}>
        {balances.length > 0 ? balances.map((bal) => (
          <BalanceCard key={bal.BalanceID || bal.LeaveTypeID} balance={bal} loading={false} />
        )) : (
          <div style={{ color: 'var(--text-muted)' }}>No balances found.</div>
        )}
      </div>

      {/* TABS */}
      <div className="tabs" style={{ display: 'flex', gap: '2rem', borderBottom: '1px solid var(--border-color)', marginBottom: '1.5rem' }}>
        {availableTabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={`tab-item ${tab === t.id ? 'active' : ''}`}
            style={{ 
              paddingBottom: '1rem', 
              fontWeight: tab === t.id ? 600 : 400,
              background: 'none', border: 'none',
              borderBottom: tab === t.id ? '2px solid var(--primary)' : 'none',
              cursor: 'pointer',
              color: tab === t.id ? 'var(--primary)' : 'var(--text-secondary)'
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* CONTENT PANELS */}
      <div className="tab-content">

        {/* EMPLOYEE VIEW - My History */}
        {tab === 'history' && (
          <div className="card shadow-sm">
            <div className="p-4" style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid var(--border-light)', paddingBottom: '1rem', marginBottom: '1rem' }}>
              <h3 style={{ fontWeight: 600, fontSize: '1.1rem' }}>My Leave History</h3>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} className="form-select" style={{ padding: '4px 8px', fontSize: '0.875rem' }}>
                   {STATUS_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button onClick={loadDashboardData} className="btn btn-ghost btn-sm" style={{ padding: '6px' }}><RefreshCw size={16} /></button>
              </div>
            </div>
            <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                  <th style={{ padding: '12px 8px' }}>Type & Details</th><th style={{ padding: '12px 8px' }}>Dates</th>
                  <th style={{ padding: '12px 8px' }}>Duration</th><th style={{ padding: '12px 8px' }}>Status</th><th style={{ padding: '12px 8px' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {myRequests.filter(req => statusMatches(req.Status || req.status, filterStatus)).map((req) => (
                  <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} isManager={false} userRole={user?.role} />
                ))}
              </tbody>
            </table>
            {myRequests.length === 0 && <div style={{ padding: '2rem', textAlign: 'center' }}><EmptyState message="No requests found." /></div>}
          </div>
        )}

        {/* MANAGER VIEW - Inbox & Team */}
        {tab === 'team' && isManager && (
          <div className="card shadow-sm">
            <div className="p-4"><h3 style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: '1rem' }}>Pending Team Approvals</h3></div>
            <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                  <th style={{ padding: '12px 8px' }}>Request Details</th><th style={{ padding: '12px 8px' }}>Employee</th>
                  <th style={{ padding: '12px 8px' }}>Dates</th><th style={{ padding: '12px 8px' }}>Days</th>
                  <th style={{ padding: '12px 8px' }}>Status</th><th style={{ padding: '12px 8px' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {teamRequests.map((req) => (
                  <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} isManager={true} userRole={user?.role} />
                ))}
              </tbody>
            </table>
            {teamRequests.length === 0 && <div style={{ padding: '2rem', textAlign: 'center' }}><EmptyState message="No pending approvals." /></div>}
          </div>
        )}

        {/* HR VIEW */}
        {tab === 'hr-dashboard' && isHR && (
          <div className="card shadow-sm">
            <div className="p-4"><h3 style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: '1rem' }}>Company-Wide Leaves</h3></div>
            <table className="table" style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--border)', color: 'var(--text-muted)' }}>
                  <th style={{ padding: '12px 8px' }}>Request Details</th><th style={{ padding: '12px 8px' }}>Employee</th>
                  <th style={{ padding: '12px 8px' }}>Dates</th><th style={{ padding: '12px 8px' }}>Status</th>
                </tr>
              </thead>
              <tbody>
                {allRequests.map((req) => (
                  <RequestRow key={req.LeaveRequestID || req.id} req={req} onAction={handleManagerAction} isManager={true} userRole={user?.role} />
                ))}
              </tbody>
            </table>
          </div>
        )}

        {tab === 'settings' && isHR && (
           <div className="card shadow-sm p-4">
             <h3 style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: '1rem' }}>HR Admin Settings</h3>
             <p>Settings panel loaded.</p>
           </div>
        )}
      </div>

      {/* Modals */}
      {isSubmitModalOpen && (
        <Modal title="Submit Leave Request" onClose={() => setIsSubmitModalOpen(false)}>
          <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmitLeave} loading={actionLoading} />
        </Modal>
      )}

      {actionLoading && (
        <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 9999 }}>
          <div style={{ background: 'var(--surface)', padding: '2rem', borderRadius: 'var(--radius-lg)' }}>
            <InlineSpinner /> Processing...
          </div>
        </div>
      )}
    </div>
  );
}
